111	fn compile_c_file(path: &str, output: &str) {
112	    let status = Command::new("gcc")
113	        .arg(path)
114	        .arg("-o")
115	        .arg(output)
116	        .arg("-lm")
117	        .status()
118	        .expect("failed to compile C code");
119	
120	    if !status.success() {
121	        panic!("C compilation failed");
122	    }
123	}
