125	fn run_compiled_c_file(path: &str) {
126	    let status = Command::new(format!("./{}", path))
127	        .status()
128	        .expect("Failed to run compiled program");
129	
130	    if !status.success() {
131	        panic!("Failed to run program");
132	    }
133	}
