166	fn run() -> Result<(), ObstructError> {
167	    let img = image::open("/home/aster/dev/rust/Obstruct/gfx/icon.png").unwrap();
168	
169	    let size = 50;
170	
171	    let img = img.thumbnail(size as u32, size as u32);
172	
173	    for y in 0..img.height() {
174	        for x in 0..img.width() {
175	            let pixel = img.get_pixel(x, y);
176	            let r = pixel[0];
177	            let g = pixel[1];
178	            let b = pixel[2];
179	
180	            print!("{}", "  ".on_truecolor(r, g, b));
181	        }
182	        println!();
183	    }
184	
185	    let args: Vec<String> = std::env::args().skip(1).collect();
186	
187	    let mut filepath = if DEBUG {
188	        "/home/aster/dev/obstruct/main.obs".to_string()
189	    } else {
190	        "".to_string()
191	    };
192	    let mut debug = true;
193	    for arg in &args {
194	        if arg == "--release" {
195	            debug = false;
196	        } else {
197	            filepath = arg.clone();
198	        }
199	    }
200	
201	    let main_program_name = Path::new(&filepath)
202	        .file_stem()
203	        .and_then(|name| name.to_str())
204	        .unwrap_or(&filepath)
205	        .to_string();
206	
207	    if main_program_name.is_empty() {
208	        eprintln!("Invalid program name");
209	        std::process::exit(1);
210	    }
211	
212	    *PROGRAM_NAME.lock().unwrap() = main_program_name.clone();
213	
214	    let mut ctx = CodeGenContext::new();
215	    let mut cte = CompileTimeEnv::new(&mut ctx);
216	    ctx.body.push_str(&format!("\nbool DEBUG = {};\n\n", debug));
217	
218	    let mut programs_to_transpile = HashMap::new();
219	    programs_to_transpile.insert(filepath, false);
220	
221	    loop {
222	        let next_file = programs_to_transpile
223	            .iter()
224	            .find(|(_, transpiled)| !**transpiled)
225	            .map(|(name, _)| name.clone());
226	
227	        match next_file {
228	            Some(name) => {
229	                // Mark it as true immediately so we don't process it again
230	                programs_to_transpile.insert(name.clone(), true);
231	
232	                let source = fs::read_to_string(&name)
233	                    .map_err(|_| ObstructError::file_not_found(name.clone()))?;
234	
235	                SOURCES.lock().unwrap().push(source.clone());
236	                let ast = parse(source);
237	
238	                ast.pre_transpile(&mut cte, &mut ctx, &mut programs_to_transpile);
239	
240	                SOURCES.lock().unwrap().pop();
241	            }
242	            None => break,
243	        }
244	    }
245	
246	    for programs in programs_to_transpile.keys() {
247	        let source = fs::read_to_string(&programs)
248	            .map_err(|_| ObstructError::file_not_found(programs.clone()))?;
249	
250	        SOURCES.lock().unwrap().push(source.clone());
251	        let ast = parse(source);
252	
253	        ast.to_c(&mut cte, &mut ctx);
254	
255	        SOURCES.lock().unwrap().pop();
256	    }
257	
258	    // Final combined C code
259	    let mut file = File::create(PROGRAM_NAME.lock().unwrap().clone() + ".c").unwrap();
260	    file.write_all(ctx.combine(&mut cte).as_bytes()).unwrap();
261	
262	    let error = ERROR.lock().unwrap().clone();
263	    error
264	}
