274	fn get_line(line: usize) -> String {
275	    let src = SOURCES.lock().unwrap();
276	    if !src.is_empty() {
277	        let source = src.last().unwrap();
278	        source
279	            .lines()
280	            .nth(line.saturating_sub(1))
281	            .unwrap_or("")
282	            .to_string()
283	    } else {
284	        String::new()
285	    }
286	}
