338	pub fn parse(source: String) -> Expr {
339	    let mut scanner = Scanner::new(source);
340	    let tokens = scanner.scan_tokens();
341	    let mut parser = Parser::new(tokens);
342	    let expr = parser.parse();
343	
344	    expr
345	}
