7	pub struct Scanner {
8	    source: String,
9	    tokens: Vec<Token>,
10	    start: usize,
11	    current: usize,
12	    line: usize,
13	    column: usize,
14	    keywords: HashMap<String, TokenType>,
15	    prev_c: char,
16	}
17	
18	impl Scanner {
19	    pub fn new(source: String) -> Self {
20	        let mut keywords = HashMap::new();
21	
22	        keywords.insert("cls".into(), TokenType::Cls);
23	        keywords.insert("ret".into(), TokenType::Ret);
24	        keywords.insert("comp".into(), TokenType::Comp);
25	        keywords.insert("stc".into(), TokenType::Stc);
26	        keywords.insert("ovr".into(), TokenType::Ovr);
27	        keywords.insert("err".into(), TokenType::Err);
28	        keywords.insert("del".into(), TokenType::Del);
29	        keywords.insert("use".into(), TokenType::Use);
30	        keywords.insert("for".into(), TokenType::For);
31	        keywords.insert("fn".into(), TokenType::Fn);
32	        keywords.insert("mac".into(), TokenType::Mac);
33	        keywords.insert("lam".into(), TokenType::Lam);
34	        keywords.insert("std".into(), TokenType::Std);
35	
36	        Scanner {
37	            source,
38	            tokens: Vec::new(),
39	            start: 0,
40	            current: 0,
41	            line: 1,
42	            column: 1,
43	            keywords,
44	            prev_c: '\0',
45	        }
46	    }
47	
48	    pub fn scan_tokens(&mut self) -> &Vec<Token> {
49	        while !self.is_at_end() {
50	            self.start = self.current;
51	            self.scan_token();
52	        }
53	
54	        self.tokens.push(Token::new(
55	            TokenType::EOF,
56	            "".into(),
57	            "".into(),
58	            self.line,
59	            self.column,
60	        ));
61	        &self.tokens
62	    }
63	
64	    fn is_at_end(&self) -> bool {
65	        self.current >= self.source.len()
66	    }
67	
68	    fn scan_token(&mut self) {
69	        let c = self.advance();
70	        match c {
71	            '(' => self.add_token(TokenType::LeftParen),
72	            ')' => self.add_token(TokenType::RightParen),
73	            '{' => self.add_token(TokenType::LeftBrace),
74	            '}' => self.add_token(TokenType::RightBrace),
75	            '[' => self.add_token(TokenType::LeftBrack),
76	            ']' => self.add_token(TokenType::RightBrack),
77	            '&' => self.add_token(TokenType::And),
78	            '|' => self.add_token(TokenType::Or),
79	            ',' => self.add_token(TokenType::Comma),
80	            '.' => self.add_token(TokenType::Dot),
81	            '%' => self.add_token(TokenType::Mod),
82	            '-' => {
83	                if self.match_char('>') {
84	                    self.add_token(TokenType::MinusRight);
85	                } else {
86	                    self.add_token(TokenType::Minus);
87	                }
88	            }
89	            '+' => self.add_token(TokenType::Plus),
90	            ';' => self.add_token(TokenType::Semicolon),
91	            ':' => {
92	                if self.match_char(':') {
93	                    self.add_token(TokenType::DoubleColon);
94	                } else {
95	                    self.add_token(TokenType::Colon);
96	                }
97	            }
98	            '*' => {
99	                if self.match_char('*') {
100	                    self.add_token(TokenType::StarStar);
101	                } else {
102	                    self.add_token(TokenType::Star);
103	                }
104	            }
105	            '~' => {
106	                if self.match_char('?') {
107	                    self.add_token(TokenType::TildeQuestionMark);
108	                } else {
109	                    self.add_token(TokenType::Tilde);
110	                }
111	            }
112	            '?' => self.add_token(TokenType::QuestionMark),
113	            '$' => {
114	                if self.match_char('?') {
115	                    self.add_token(TokenType::DollarQuestionMark);
116	                } else {
117	                    self.add_token(TokenType::Dollar);
118	                }
119	            }
120	            '^' => {
121	                if self.match_char('^') {
122	                    self.add_token(TokenType::DoubleUpArrow);
123	                } else {
124	                    self.add_token(TokenType::UpArrow);
125	                }
126	            }
127	            '!' => {
128	                if self.match_char('=') {
129	                    self.add_token(TokenType::BangEqual);
130	                } else {
131	                    self.add_token(TokenType::Bang);
132	                }
133	            }
134	            '=' => {
135	                if self.match_char('=') {
136	                    self.add_token(TokenType::EqualEqual);
137	                } else {
138	                    self.add_token(TokenType::Equal);
139	                }
140	            }
141	            '<' => {
142	                if self.match_char('=') {
143	                    self.add_token(TokenType::LessEqual);
144	                } else if self.match_char('<') {
145	                    self.add_token(TokenType::LessLess);
146	                } else {
147	                    self.add_token(TokenType::Less);
148	                }
149	            }
150	            '>' => {
151	                if self.match_char('=') {
152	                    self.add_token(TokenType::GreaterEqual);
153	                } else if self.match_char('>') {
154	                    self.add_token(TokenType::GreaterGreater);
155	                } else {
156	                    self.add_token(TokenType::Greater);
157	                }
158	            }
159	            '#' => {
160	                self.add_token(TokenType::Hash);
161	            }
162	            '@' => self.add_token(TokenType::At),
163	            '£' => self.add_token(TokenType::Pound),
164	            '¬' => self.add_token(TokenType::NotSign),
165	            '/' => {
166	                if self.match_char('/') {
167	                    // Single-line comment
168	                    while self.peek() != '\n' && !self.is_at_end() {
169	                        self.advance();
170	                    }
171	                } else if self.match_char('*') {
172	                    // Multi-line comment
173	                    self.block_comment();
174	                } else {
175	                    self.add_token(TokenType::Slash);
176	                }
177	            }
178	            '\\' => self.add_token(TokenType::BackSlash),
179	            ' ' | '\r' | '\t' | '\n' => {}
180	            '`' => self.backtick(),
181	            '"' => self.string(),
182	            '\'' => self.character(),
183	            _ => {
184	                if c.is_ascii_digit() {
185	                    self.number();
186	                } else if self.alpha(c) {
187	                    self.identifier();
188	                } else {
189	                    error(
190	                        Span {
191	                            line: self.line,
192	                            column: self.column,
193	                        },
194	                        "Unexpected character.",
195	                        "scanning",
196	                    );
197	                }
198	            }
199	        }
200	    }
201	
202	    fn advance(&mut self) -> char {
203	        let c = self.source[self.current..].chars().next().unwrap();
204	        self.current += c.len_utf8();
205	
206	        if c == '\n' {
207	            self.line += 1;
208	            self.column = 1;
209	        } else {
210	            self.column += 1;
211	        }
212	
213	        c
214	    }
215	
216	    fn add_token(&mut self, token_type: TokenType) {
217	        self.add_token_literal(token_type, "".into());
218	    }
219	
220	    fn add_token_literal(&mut self, token_type: TokenType, literal: String) {
221	        let text = self.source[self.start..self.current].to_string();
222	
223	        let token_column = self.column - text.chars().count();
224	
225	        self.tokens.push(Token::new(
226	            token_type,
227	            text,
228	            literal,
229	            self.line,
230	            token_column.max(1),
231	        ));
232	    }
233	
234	    fn match_char(&mut self, expected: char) -> bool {
235	        if self.is_at_end() {
236	            return false;
237	        }
238	
239	        if self.peek() != expected {
240	            return false;
241	        }
242	
243	        self.advance();
244	        true
245	    }
246	
247	    fn peek(&self) -> char {
248	        if self.is_at_end() {
249	            '\0'
250	        } else {
251	            self.source[self.current..].chars().next().unwrap()
252	        }
253	    }
254	
255	    fn peek_next(&self) -> char {
256	        let mut chars = self.source[self.current..].chars();
257	        chars.next();
258	        chars.next().unwrap_or('\0')
259	    }
260	
261	    fn alpha(&mut self, c: char) -> bool {
262	        let output =
263	            (c.is_ascii_alphabetic() || c == '_' || c == '¬') && !(c == '_' && self.prev_c == '_');
264	        self.prev_c = c;
265	        output
266	    }
267	
268	    fn alpha_numeric(&mut self, c: char) -> bool {
269	        self.alpha(c) || c.is_ascii_digit()
270	    }
271	
272	    fn string(&mut self) {
273	        let mut value = String::new();
274	
275	        while !self.is_at_end() {
276	            let c = self.advance();
277	
278	            match c {
279	                '"' => {
280	                    // End of string
281	                    self.add_token_literal(TokenType::String, value);
282	                    return;
283	                }
284	                '\\' => {
285	                    if self.is_at_end() {
286	                        error(
287	                            Span {
288	                                line: self.line,
289	                                column: self.column,
290	                            },
291	                            "Unterminated escape sequence in string.",
292	                            "lexing",
293	                        );
294	                        return;
295	                    }
296	
297	                    let esc = self.advance();
298	                    match esc {
299	                        'n' => value.push('\n'),
300	                        't' => value.push('\t'),
301	                        'r' => value.push('\r'),
302	                        '\\' => value.push('\\'),
303	                        '"' => value.push('"'),
304	                        _ => {
305	                            error(
306	                                Span {
307	                                    line: self.line,
308	                                    column: self.column,
309	                                },
310	                                &format!("Invalid escape sequence: \\{}", esc),
311	                                "lexing",
312	                            );
313	                            return;
314	                        }
315	                    }
316	                }
317	                _ => value.push(c),
318	            }
319	        }
320	
321	        error(
322	            Span {
323	                line: self.line,
324	                column: self.column,
325	            },
326	            "Unterminated string literal.",
327	            "lexing",
328	        );
329	    }
330	
331	    fn number(&mut self) {
332	        while self.peek().is_ascii_digit() {
333	            self.advance();
334	        }
335	
336	        // Look for fractional part
337	        if self.peek() == '.' && self.peek_next().is_ascii_digit() {
338	            self.advance(); // consume '.'
339	            while self.peek().is_ascii_digit() {
340	                self.advance();
341	            }
342	            let value = self.source[self.start..self.current].to_string();
343	            self.add_token_literal(TokenType::Float, value);
344	        } else {
345	            let value = self.source[self.start..self.current].to_string();
346	            self.add_token_literal(TokenType::Int, value);
347	        }
348	    }
349	
350	    fn identifier(&mut self) {
351	        while self.alpha_numeric(self.peek()) {
352	            self.advance();
353	        }
354	
355	        // Handle '::' type sequences like 'str::i32'
356	        while self.peek() == ':' && self.peek_next() == ':' {
357	            self.advance(); // consume first ':'
358	            self.advance(); // consume second ':'
359	
360	            // continue scanning the next identifier part
361	            while self.alpha_numeric(self.peek()) {
362	                self.advance();
363	            }
364	        }
365	
366	        let text = self.source[self.start..self.current].to_string();
367	        if let Some(token_type) = self.keywords.get(&text) {
368	            self.add_token(*token_type);
369	        } else {
370	            self.add_token(TokenType::Ident);
371	        }
372	    }
373	
374	    fn character(&mut self) {
375	        if self.is_at_end() {
376	            error(
377	                Span {
378	                    line: self.line,
379	                    column: self.column,
380	                },
381	                "Unterminated character literal.",
382	                "lexing",
383	            );
384	            return;
385	        }
386	
387	        let c = self.advance();
388	        let value = if c == '\\' {
389	            if self.is_at_end() {
390	                error(
391	                    Span {
392	                        line: self.line,
393	                        column: self.column,
394	                    },
395	                    "Unterminated escape sequence.",
396	                    "lexing",
397	                );
398	                return;
399	            }
400	            let esc = self.advance();
401	            match esc {
402	                'n' => "\n".to_string(),
403	                't' => "\t".to_string(),
404	                '\\' => "\\".to_string(),
405	                '\'' => "'".to_string(),
406	                'r' => "\r".to_string(),
407	                _ => {
408	                    error(
409	                        Span {
410	                            line: self.line,
411	                            column: self.column,
412	                        },
413	                        &format!("Invalid escape sequence: \\{}", esc),
414	                        "lexing",
415	                    );
416	                    return;
417	                }
418	            }
419	        } else {
420	            c.to_string()
421	        };
422	
423	        if self.peek() != '\'' {
424	            error(
425	                Span {
426	                    line: self.line,
427	                    column: self.column,
428	                },
429	                "Character literal too long or missing closing quote.",
430	                "lexing",
431	            );
432	            return;
433	        }
434	
435	        self.advance(); // Consume closing quote
436	        self.add_token_literal(TokenType::Char, value);
437	    }
438	
439	    fn backtick(&mut self) {
440	        if self.is_at_end() {
441	            error(
442	                Span {
443	                    line: self.line,
444	                    column: self.column,
445	                },
446	                "Expected character after backtick (`)",
447	                "lexing",
448	            );
449	            return;
450	        }
451	
452	        let c = self.advance();
453	        match c {
454	            'f' => self.add_token(TokenType::False),
455	            't' => self.add_token(TokenType::True),
456	            's' => self.tokens.push(Token::new(
457	                TokenType::String,
458	                String::new(),
459	                String::new(),
460	                self.line,
461	                self.column,
462	            )),
463	            'v' => self.add_token(TokenType::This),
464	            _ => {
465	                error(
466	                    Span {
467	                        line: self.line,
468	                        column: self.column,
469	                    },
470	                    "Invalid character after backtick (`)",
471	                    "lexing",
472	                );
473	                return;
474	            }
475	        }
476	
477	        if self.alpha(self.peek()) {
478	            error(
479	                Span {
480	                    line: self.line,
481	                    column: self.column,
482	                },
483	                "Only a single character should be after a backtick (`)",
484	                "lexing",
485	            );
486	        }
487	    }
488	
489	    fn block_comment(&mut self) {
490	        while !self.is_at_end() {
491	            if self.peek() == '*' {
492	                self.advance();
493	                if self.peek() == '/' {
494	                    self.advance();
495	                    return;
496	                }
497	            } else {
498	                self.advance();
499	            }
500	        }
501	
502	        error(
503	            Span {
504	                line: self.line,
505	                column: self.column,
506	            },
507	            "Unterminated block comment.",
508	            "lexing",
509	        );
510	    }
511	}
