1	use crate::expr::UseKind;
2	use crate::span::Span;
3	use crate::token_type::TokenType::Pound;
4	use crate::type_env::{nil_type, Type};
5	use crate::{error, expr::Expr, token::Token, token_type::TokenType};
6	
7	pub struct Parser<'a> {
8	    tokens: &'a [Token],
9	    current: usize,
10	}
11	
12	impl<'a> Parser<'a> {
13	    pub fn new(tokens: &'a [Token]) -> Self {
14	        Self { tokens, current: 0 }
15	    }
16	
17	    // ---------- ENTRY ----------
18	    pub fn parse(&mut self) -> Expr {
19	        let mut statements = Vec::new();
20	
21	        while !self.is_at_end() {
22	            statements.push(Box::new(self.statement()));
23	            if !self.match_any(&[TokenType::Semicolon]) && !self.is_at_end() {
24	                let t = self.peek();
25	                error(
26	                    self.get_span(),
27	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
28	                    "parsing",
29	                );
30	                self.advance();
31	            }
32	        }
33	
34	        Expr::StmtBlock(statements, self.get_span())
35	    }
36	
37	    // ---------- STATEMENTS ----------
38	    fn statement(&mut self) -> Expr {
39	        if self.match_any(&[TokenType::Dollar]) {
40	            return self.print();
41	        }
42	
43	        if self.match_any(&[TokenType::Ret]) {
44	            return self.return_stmt();
45	        }
46	
47	        if self.match_any(&[Pound]) {
48	            return self.while_loop();
49	        }
50	
51	        if self.match_any(&[TokenType::Fn]) {
52	            return self.define_function();
53	        }
54	
55	        if self.match_any(&[TokenType::Hash]) {
56	            return self.declaration();
57	        }
58	
59	        if self.match_any(&[TokenType::Del]) {
60	            return self.delete();
61	        }
62	
63	        if self.match_any(&[TokenType::QuestionMark]) {
64	            return self.if_statement(false);
65	        }
66	
67	        if self.check(TokenType::Ident) && self.peek_next(TokenType::Equal) {
68	            self.advance();
69	            return self.assignment();
70	        }
71	
72	        if self.match_any(&[TokenType::Use]) {
73	            return self.use_file();
74	        }
75	
76	        if self.match_any(&[TokenType::For]) {
77	            return self.for_loop();
78	        }
79	
80	        Expr::Stmt(Box::new(self.expression()))
81	    }
82	
83	    // ---------- USE ------------
84	
85	    fn use_file(&mut self) -> Expr {
86	        let kind = if self.match_any(&[TokenType::Std]) {
87	            UseKind::Std
88	        } else {
89	            UseKind::Normal
90	        };
91	        self.consume(TokenType::String, "Expected file name after 'use' keyword");
92	        Expr::Use {
93	            kind,
94	            path: self.previous().literal,
95	            span: self.get_span(),
96	        }
97	    }
98	
99	    // ---------- BLOCK ----------
100	    fn statement_block(&mut self) -> Expr {
101	        let mut statements = Vec::new();
102	
103	        while !self.check(TokenType::RightBrace) && !self.is_at_end() {
104	            let statement = self.statement();
105	
106	            if !self.check(TokenType::Semicolon) && !self.check(TokenType::RightBrace) {
107	                let t = self.peek();
108	                error(
109	                    self.get_span(),
110	                    format!("Expected ';' after statement. Found '{}'", t.token_type).as_str(),
111	                    "parsing",
112	                );
113	                self.advance();
114	            }
115	            if self.match_any(&[TokenType::Semicolon]) {
116	                statements.push(Box::new(Expr::Discard(Box::new(statement))));
117	            } else {
118	                statements.push(Box::new(statement));
119	            }
120	        }
121	
122	        self.consume(TokenType::RightBrace, "Expected '}' after block.");
123	        Expr::StmtBlockWithScope(statements, self.get_span())
124	    }
125	
126	    // ---------- DELETE VAR -----------
127	
128	    fn delete(&mut self) -> Expr {
129	        if self.match_any(&[TokenType::Ident]) {
130	            Expr::Delete(self.previous().lexeme)
131	        } else {
132	            error(
133	                self.get_span(),
134	                "Expected variable name after 'del'.",
135	                "parsing",
136	            );
137	            Expr::Nothing()
138	        }
139	    }
140	
141	    // ---------- NEW CLASS -----------
142	
143	    // ---------- WHILE LOOP -----------
144	
145	    fn while_loop(&mut self) -> Expr {
146	        let cond = self.expression();
147	        // self.current += 1;
148	        let block = if self.match_any(&[TokenType::LeftBrace]) {
149	            self.statement_block()
150	        } else {
151	            error(
152	                self.get_span(),
153	                ("Expected '{' after 'while' condition, found '".to_string()
154	                    + self.previous().lexeme.as_str()
155	                    + "'")
156	                    .as_str(),
157	                "parsing",
158	            );
159	            Expr::Nothing()
160	        };
161	
162	        Expr::While(Box::new(cond), Box::new(block))
163	    }
164	
165	    // ----------- FOR LOOP -----------
166	
167	    fn for_loop(&mut self) -> Expr {
168	        self.consume(TokenType::Ident, "Expected identifier after 'For' token");
169	        let loopee = self.previous().lexeme;
170	        self.consume(TokenType::Colon, "Expected ':' after loopee");
171	        let looper = self.expression();
172	        self.consume(TokenType::LeftBrace, "Expected '{' after looper");
173	        let block = self.statement_block();
174	
175	        Expr::For(loopee, Box::new(looper), Box::new(block), self.get_span())
176	    }
177	
178	    // ---------- DECLARATION ----------
179	    fn declaration(&mut self) -> Expr {
180	        let is_mutable = self.match_any(&[TokenType::At]);
181	
182	        self.consume(TokenType::Ident, "Expected variable name.");
183	        let name = self.previous().lexeme.clone();
184	
185	        let var_type = if self.match_any(&[TokenType::Colon]) {
186	            Some(self.get_type())
187	        } else {
188	            None
189	        };
190	        let expr = if self.match_any(&[TokenType::Equal]) {
191	            Some(Box::new(self.expression()))
192	        } else {
193	            None
194	        };
195	
196	        if var_type.is_none() && expr.is_none() {
197	            let span = self.get_span();
198	            error(
199	                span,
200	                "Expected type or expression or both, got neither",
201	                "parsing",
202	            );
203	        }
204	        Expr::Declare(name, var_type, expr, is_mutable, self.get_span())
205	    }
206	
207	    // ---------- ASSIGNMENT ----------
208	    fn assignment(&mut self) -> Expr {
209	        let name = self.previous().lexeme.clone();
210	        self.consume(TokenType::Equal, "Expected '=' after identifier.");
211	        let span = self.get_span();
212	        Expr::Assign(name, Box::new(self.expression()), span)
213	    }
214	
215	    // ------- IF / ELSE IF / ELSE ----
216	
217	    fn if_statement(&mut self, is_expr: bool) -> Expr {
218	        let if_cond = self.expression();
219	        // self.current += 1;
220	        let if_block = if self.match_any(&[TokenType::LeftBrace]) {
221	            self.statement_block()
222	        } else {
223	            error(
224	                self.get_span(),
225	                ("Expected '{' after 'if' condition, found '".to_string()
226	                    + self.previous().lexeme.as_str()
227	                    + "'")
228	                    .as_str(),
229	                "parsing",
230	            );
231	            Expr::Nothing()
232	        };
233	
234	        let mut else_block = None;
235	
236	        if self.match_any(&[TokenType::TildeQuestionMark]) {
237	            else_block = Some(Box::new(self.if_statement(is_expr)));
238	        } else if self.match_any(&[TokenType::Tilde]) {
239	            self.consume(TokenType::LeftBrace, "Expected '{' after 'TILDE'.");
240	            else_block = Some(Box::new(self.statement_block()));
241	        }
242	
243	        Expr::If(Box::new(if_cond), Box::new(if_block), else_block, is_expr)
244	    }
245	    // ---------- PRINT ---------------
246	    fn print(&mut self) -> Expr {
247	        if self.peek().token_type == TokenType::Dollar {
248	            self.advance();
249	            Expr::StmtBlock(
250	                vec![
251	                    Box::new(self.print()),
252	                    Box::new(Expr::Print(
253	                        Box::new(Expr::Str("\n".to_string())),
254	                        self.get_span(),
255	                    )),
256	                ],
257	                self.get_span(),
258	            )
259	        } else if self.peek().token_type == TokenType::Semicolon {
260	            Expr::Nothing()
261	        } else {
262	            Expr::Print(Box::new(self.expression()), self.get_span())
263	        }
264	    }
265	
266	    // ---------- FUNCTIONS ------------
267	
268	    fn define_function(&mut self) -> Expr {
269	        let mut generic_params = vec![];
270	
271	        if self.match_any(&[TokenType::LessLess]) {
272	            loop {
273	                self.consume(TokenType::Ident, "Expected generic name");
274	                generic_params.push(self.previous().lexeme);
275	
276	                if !self.match_any(&[TokenType::Comma]) {
277	                    break;
278	                }
279	            }
280	            self.consume(TokenType::GreaterGreater, "Expected '>'");
281	        }
282	
283	        let name = self.advance().lexeme;
284	
285	        let start_span = self.get_span();
286	
287	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
288	            let mut parameters = vec![];
289	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
290	                let name = self.advance().lexeme;
291	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
292	                let var_type = self.get_type();
293	                parameters.push((name, var_type));
294	                if !self.match_any(&[TokenType::Comma]) {
295	                    break;
296	                }
297	            }
298	
299	            self.consume(
300	                TokenType::RightParen,
301	                "Expected ')' after function parameters.",
302	            );
303	            parameters
304	        } else {
305	            vec![]
306	        };
307	
308	        let return_type = if !self.check(TokenType::LeftBrace) {
309	            Some(self.get_type())
310	        } else {
311	            None
312	        };
313	
314	        self.consume(
315	            TokenType::LeftBrace,
316	            "Expected '{' after function declaration.",
317	        );
318	
319	        let body = Box::new(self.statement_block());
320	
321	        Expr::DeclareFunction(
322	            name,
323	            body,
324	            return_type,
325	            parameters,
326	            generic_params,
327	            start_span,
328	        )
329	    }
330	
331	    fn define_lambda(&mut self) -> Expr {
332	        let mut generic_params = vec![];
333	
334	        if self.match_any(&[TokenType::LessLess]) {
335	            loop {
336	                self.consume(TokenType::Ident, "Expected generic name");
337	                generic_params.push(self.previous().lexeme);
338	
339	                if !self.match_any(&[TokenType::Comma]) {
340	                    break;
341	                }
342	            }
343	            self.consume(TokenType::GreaterGreater, "Expected '>'");
344	        }
345	
346	        let parameters: Vec<(String, Type)> = if self.match_any(&[TokenType::LeftParen]) {
347	            let mut parameters = vec![];
348	            while !self.is_at_end() && !self.check(TokenType::RightParen) {
349	                let name = self.advance().lexeme;
350	                self.consume(TokenType::Colon, "Expected ':' after parameter name.");
351	                let var_type = self.get_type();
352	                parameters.push((name, var_type));
353	                if !self.match_any(&[TokenType::Comma]) {
354	                    break;
355	                }
356	            }
357	
358	            self.consume(
359	                TokenType::RightParen,
360	                "Expected ')' after function parameters.",
361	            );
362	            parameters
363	        } else {
364	            vec![]
365	        };
366	
367	        let return_type = if !self.check(TokenType::LeftBrace) {
368	            self.get_type()
369	        } else {
370	            nil_type()
371	        };
372	
373	        self.consume(
374	            TokenType::LeftBrace,
375	            "Expected '{' after function declaration.",
376	        );
377	
378	        let body = Box::new(self.statement_block());
379	
380	        Expr::Function(body, return_type, parameters, generic_params)
381	    }
382	
383	    fn return_stmt(&mut self) -> Expr {
384	        let value = self.expression();
385	        Expr::Return(Box::new(value), self.get_span())
386	    }
387	
388	    fn call_function(&mut self) -> Expr {
389	        let name = self.previous().lexeme;
390	
391	        let mut generics = vec![];
392	
393	        if self.match_any(&[TokenType::LessLess]) {
394	            loop {
395	                generics.push(self.get_type());
396	
397	                if !self.match_any(&[TokenType::Comma]) {
398	                    break;
399	                }
400	            }
401	            self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
402	        }
403	
404	        self.consume(TokenType::LeftParen, "Expected '(' after function name.");
405	
406	        let mut arguments = vec![];
407	
408	        if !self.check(TokenType::RightParen) {
409	            loop {
410	                arguments.push(Box::new(self.expression()));
411	                if !self.match_any(&[TokenType::Comma]) {
412	                    break;
413	                }
414	            }
415	        }
416	
417	        self.consume(TokenType::RightParen, "Missing ')' after function call.");
418	
419	        Expr::CallFunc(name, generics, arguments, self.get_span())
420	    }
421	
422	    // ---------- EXPRESSIONS ----------
423	    fn expression(&mut self) -> Expr {
424	        self.bools()
425	    }
426	
427	    fn bools(&mut self) -> Expr {
428	        let mut expr = self.compare();
429	
430	        while self.match_any(&[TokenType::And, TokenType::Or]) {
431	            let op = self.previous().token_type;
432	            let right = self.compare();
433	            expr = match op {
434	                TokenType::And => Expr::And(Box::new(expr), Box::new(right), self.get_span()),
435	                TokenType::Or => Expr::Or(Box::new(expr), Box::new(right), self.get_span()),
436	                _ => unreachable!(),
437	            };
438	        }
439	
440	        expr
441	    }
442	
443	    fn compare(&mut self) -> Expr {
444	        let mut expr = self.term();
445	
446	        while self.match_any(&[
447	            TokenType::EqualEqual,
448	            TokenType::BangEqual,
449	            TokenType::Greater,
450	            TokenType::GreaterEqual,
451	            TokenType::Less,
452	            TokenType::LessEqual,
453	        ]) {
454	            let op = self.previous().token_type;
455	            let right = self.term();
456	            expr = match op {
457	                TokenType::EqualEqual => {
458	                    Expr::EqualEqual(Box::new(expr), Box::new(right), self.get_span())
459	                }
460	                TokenType::BangEqual => {
461	                    Expr::BangEqual(Box::new(expr), Box::new(right), self.get_span())
462	                }
463	                TokenType::Greater => {
464	                    Expr::Greater(Box::new(expr), Box::new(right), self.get_span())
465	                }
466	                TokenType::GreaterEqual => {
467	                    Expr::GreaterEqual(Box::new(expr), Box::new(right), self.get_span())
468	                }
469	                TokenType::Less => Expr::Less(Box::new(expr), Box::new(right), self.get_span()),
470	                TokenType::LessEqual => {
471	                    Expr::LessEqual(Box::new(expr), Box::new(right), self.get_span())
472	                }
473	                _ => unreachable!(),
474	            };
475	        }
476	
477	        expr
478	    }
479	
480	    fn term(&mut self) -> Expr {
481	        let mut expr = self.factor();
482	
483	        while self.match_any(&[TokenType::Plus, TokenType::Minus]) {
484	            let op = self.previous().token_type;
485	            let right = self.factor();
486	            expr = match op {
487	                TokenType::Plus => Expr::Add(Box::new(expr), Box::new(right), self.get_span()),
488	                TokenType::Minus => Expr::Sub(Box::new(expr), Box::new(right), self.get_span()),
489	                _ => unreachable!(),
490	            };
491	        }
492	
493	        expr
494	    }
495	
496	    fn factor(&mut self) -> Expr {
497	        let mut expr = self.unary();
498	
499	        while self.match_any(&[TokenType::Star, TokenType::Slash, TokenType::Mod]) {
500	            let op = self.previous().token_type;
501	            let right = self.unary();
502	            expr = match op {
503	                TokenType::Star => Expr::Mult(Box::new(expr), Box::new(right), self.get_span()),
504	                TokenType::Slash => Expr::Div(Box::new(expr), Box::new(right), self.get_span()),
505	                TokenType::Mod => Expr::Mod(Box::new(expr), Box::new(right), self.get_span()),
506	                _ => unreachable!(),
507	            };
508	        }
509	
510	        expr
511	    }
512	
513	    fn unary(&mut self) -> Expr {
514	        if self.match_any(&[TokenType::Minus]) {
515	            return Expr::Sub(
516	                Box::new(Expr::Nothing()),
517	                Box::new(self.unary()),
518	                self.get_span(),
519	            );
520	        }
521	
522	        if self.match_any(&[TokenType::Plus]) {
523	            return Expr::Add(
524	                Box::new(Expr::Nothing()),
525	                Box::new(self.unary()),
526	                self.get_span(),
527	            );
528	        }
529	
530	        if self.match_any(&[TokenType::Bang]) {
531	            return Expr::Not(Box::new(self.unary()));
532	        }
533	
534	        if self.match_any(&[TokenType::And]) {
535	            // Make a reference to the variable itself
536	            return if self.check(TokenType::Ident) {
537	                self.advance(); // consume the identifier
538	                let var_name = self.previous().lexeme.clone();
539	                Expr::CallFunc(
540	                    "ref::new".into(),
541	                    vec![],
542	                    vec![Box::new(Expr::Str(var_name))],
543	                    self.get_span(),
544	                )
545	            } else {
546	                error(self.get_span(), "Expected identifier after '&'.", "parsing");
547	                Expr::Nothing()
548	            };
549	        }
550	
551	        if self.match_any(&[TokenType::Star]) {
552	            let expr = self.unary();
553	            return Expr::CallFunc(
554	                "ref::deref".into(),
555	                vec![],
556	                vec![Box::new(expr)],
557	                self.get_span(),
558	            );
559	        }
560	
561	        self.power()
562	    }
563	
564	    fn power(&mut self) -> Expr {
565	        let mut expr = self.nth();
566	
567	        while self.match_any(&[TokenType::StarStar]) {
568	            expr = Expr::Power(Box::new(expr), Box::new(self.nth()), self.get_span());
569	        }
570	
571	        expr
572	    }
573	    fn nth(&mut self) -> Expr {
574	        let val = self.primary();
575	        if self.match_any(&[TokenType::LeftBrack]) {
576	            let expr = self.expression();
577	            self.consume(TokenType::RightBrack, "Expected ']' after indexing.");
578	            Expr::Nth(Box::new(val), Box::new(expr), self.get_span())
579	        } else {
580	            val
581	        }
582	    }
583	
584	    fn vector_lit(&mut self) -> Expr {
585	        if self.match_any(&[TokenType::LeftBrace]) {
586	            let mut exprs = vec![];
587	
588	            let mut last_expr = false;
589	            while !self.match_any(&[TokenType::RightBrace]) && !last_expr {
590	                let expr = self.expression();
591	                exprs.push(expr);
592	                if !self.match_any(&[TokenType::Comma]) {
593	                    last_expr = true;
594	                }
595	            }
596	
597	            Expr::Vector(exprs)
598	        } else {
599	            self.consume(TokenType::LeftBrace, "Expected '{' after '\\''.");
600	            Expr::Nothing()
601	        }
602	    }
603	
604	    fn array_lit(&mut self) -> Expr {
605	        let mut exprs = vec![];
606	
607	        let mut last_expr = false;
608	        while !self.match_any(&[TokenType::RightBrack]) && !last_expr {
609	            let expr = self.expression();
610	            exprs.push(expr);
611	            if !self.match_any(&[TokenType::Comma]) {
612	                last_expr = true;
613	            }
614	        }
615	
616	        Expr::Array(exprs)
617	    }
618	
619	    // ---------- PRIMARY ----------
620	    fn primary(&mut self) -> Expr {
621	        if self.match_any(&[TokenType::LeftBrace]) {
622	            return self.statement_block();
623	        }
624	
625	        if self.check(TokenType::Ident)
626	            && (self.peek_next(TokenType::LeftParen) || self.peek_next(TokenType::LessLess))
627	        {
628	            self.consume(TokenType::Ident, "THIS SHOULD BE UNREACHABLE.");
629	            return self.call_function();
630	        }
631	
632	        if self.match_any(&[TokenType::Ident]) {
633	            return Expr::Variable(self.previous().lexeme.clone(), self.get_span());
634	        }
635	
636	        if self.match_any(&[TokenType::Float]) {
637	            return Expr::Float(self.previous().literal.parse().unwrap_or(0.0));
638	        }
639	
640	        if self.match_any(&[TokenType::Int]) {
641	            return Expr::Int(self.previous().literal.parse().unwrap_or(0));
642	        }
643	
644	        if self.match_any(&[TokenType::True]) {
645	            return Expr::Bool(true);
646	        }
647	
648	        if self.match_any(&[TokenType::False]) {
649	            return Expr::Bool(false);
650	        }
651	
652	        if self.match_any(&[TokenType::String]) {
653	            return Expr::Str(self.previous().literal.clone());
654	        }
655	
656	        if self.match_any(&[TokenType::Char]) {
657	            return Expr::Char(self.previous().literal.clone());
658	        }
659	
660	        if self.match_any(&[TokenType::LeftParen]) {
661	            let expr = self.expression();
662	            self.consume(TokenType::RightParen, "Expected ')'.");
663	            return expr;
664	        }
665	
666	        if self.match_any(&[TokenType::QuestionMark]) {
667	            return self.if_statement(true);
668	        }
669	
670	        if self.match_any(&[TokenType::This]) {
671	            return Expr::This(self.get_span());
672	        }
673	
674	        if self.match_any(&[TokenType::Lam]) {
675	            return self.define_lambda();
676	        }
677	
678	        if self.match_any(&[TokenType::BackSlash]) {
679	            return self.vector_lit();
680	        }
681	
682	        if self.match_any(&[TokenType::LeftBrack]) {
683	            return self.array_lit();
684	        }
685	
686	        Expr::Nothing()
687	    }
688	
689	    fn get_type(&mut self) -> Type {
690	        if self.match_any(&[TokenType::Ident]) {
691	            let name = self.previous().lexeme.clone();
692	
693	            // Generic placeholder
694	            if name.chars().next().unwrap().is_uppercase() && !self.check(TokenType::LessLess) {
695	                return Type::conceptual(&name);
696	            }
697	
698	            if self.match_any(&[TokenType::LessLess]) {
699	                let mut gens = vec![];
700	
701	                loop {
702	                    gens.push(self.get_type());
703	                    if !self.match_any(&[TokenType::Comma]) {
704	                        break;
705	                    }
706	                }
707	
708	                self.consume(TokenType::GreaterGreater, "Expected '>' after generics");
709	                return Type::with_generics(&name, gens);
710	            }
711	
712	            return Type::simple(&name);
713	        } else if self.match_any(&[TokenType::LeftBrack]) {
714	            let mut gens = vec![];
715	
716	            loop {
717	                gens.push(self.get_type());
718	                if !self.match_any(&[TokenType::Comma]) {
719	                    break;
720	                }
721	            }
722	
723	            self.consume(TokenType::RightBrack, "Expected '>' after generics");
724	            return Type::with_generics("arr", gens);
725	        }
726	
727	        nil_type()
728	    }
729	
730	    // ---------- UTIL ----------
731	    fn get_span(&self) -> Span {
732	        let token = self.previous();
733	        Span {
734	            line: token.line,
735	            column: token.column,
736	        }
737	    }
738	
739	    fn match_any(&mut self, types: &[TokenType]) -> bool {
740	        for t in types {
741	            if self.check(*t) {
742	                self.advance();
743	                return true;
744	            }
745	        }
746	        false
747	    }
748	    fn check(&self, token_type: TokenType) -> bool {
749	        !self.is_at_end() && self.peek().token_type == token_type
750	    }
751	
752	    fn peek_next(&self, token_type: TokenType) -> bool {
753	        self.tokens
754	            .get(self.current + 1)
755	            .map(|t| t.token_type == token_type)
756	            .unwrap_or(false)
757	    }
758	
759	    fn peek_next_next(&self, token_type: TokenType) -> bool {
760	        self.tokens
761	            .get(self.current + 2)
762	            .map(|t| t.token_type == token_type)
763	            .unwrap_or(false)
764	    }
765	
766	    fn consume(&mut self, token_type: TokenType, message: &str) -> Token {
767	        if self.check(token_type) {
768	            self.advance()
769	        } else {
770	            let t = self.peek();
771	            error(
772	                self.get_span(),
773	                format!("{} Found: {}", message, t.token_type).as_str(),
774	                "parsing",
775	            );
776	            self.advance();
777	            Token::nil()
778	        }
779	    }
780	
781	    fn advance(&mut self) -> Token {
782	        if !self.is_at_end() {
783	            self.current += 1;
784	        }
785	        self.previous()
786	    }
787	
788	    fn is_at_end(&self) -> bool {
789	        self.peek().token_type == TokenType::EOF
790	    }
791	
792	    fn peek(&self) -> Token {
793	        self.tokens
794	            .get(self.current)
795	            .cloned()
796	            .unwrap_or_else(Token::nil)
797	    }
798	
799	    fn previous(&self) -> Token {
800	        self.tokens
801	            .get(self.current.saturating_sub(1))
802	            .cloned()
803	            .unwrap_or_else(Token::nil)
804	    }
805	}
806	
807	// Grammar:
808	/*
809	statement_block -> "{" ( statement )* "}"
810	statement       -> ( print | declaration | expression | return | function ) ";"
811	
812	print           -> "$" ( "$" )? expression
813	declaration     -> "#" ( "@" )? IDENTIFIER ( ":" type )? ( "=" expression )? // need one or both
814	return          -> "ret" expression
815	while           -> "£" expression statement_block
816	
817	if_statement    -> "?" expression statement_block ( "~?" expression statement_block )* ( "~" statement_block )?
818	function_call   -> IDENTIFIER "(" (expression)* ")"
819	function        -> "fn" ( "<<" IDENTIFIER* ">>" )? IDENTIFIER ( "(" (IDENTIFIER ":" IDENTIFIER)* ")" )? type? statement_block
820	
821	type            -> IDENTIFIER | "[" type* "]" | "<<" type* ">>"
822	
823	expression      -> bool
824	bool            -> compare ( ( "&" | "|" ) compare )*
825	compare         -> term ( ( "==" | ">=" | "<=" | ">" | "<" | "!=" ) term )*
826	term            -> factor ( ( "+" | "-" ) factor )*
827	factor          -> unary ( ( "*" | "/" | "%" ) unary )*
828	unary           -> ( "-" | "+" ) unary | power
829	power           -> nth ( ( "**" ) nth )*
830	nth             -> primary ( "[" expression "]" )?
831	primary         -> NUMBER | STRING | BOOLEAN | IDENTIFIER | "(" expression ")" | statement_block | if_statement | function_call
832	
833	*/
834

