238	            "_greater_equal".to_string(),
239	            false,
240	            Type::with_generics(
241	                "func",
242	                vec![
243	                    Type::simple("f64"),
244	                    Type::simple("f64"),
245	                    Type::simple("bool"),
246	                ],
247	            ),
248	        );
249	        this.add_func_type(
250	            Type::simple("bool"),
251	            vec![Type::simple("f64"), Type::simple("f64")],
252	            ctx,
253	            Span::empty(),
254	        );
255	
256	        // Declare and register _less_equal: func(f64, f64) -> bool
257	        this.declare_global_var(
258	            "_less_equal".to_string(),
259	            false,
260	            Type::with_generics(
261	                "func",
262	                vec![
263	                    Type::simple("f64"),
264	                    Type::simple("f64"),
265	                    Type::simple("bool"),
266	                ],
267	            ),
268	        );
269	        this.add_func_type(
270	            Type::simple("bool"),
271	            vec![Type::simple("f64"), Type::simple("f64")],
272	            ctx,
273	            Span::empty(),
274	        );
275	
276	        this
277	    }
278	
279	    // Scope Management
280	
281	    pub fn push_scope(&mut self) {
282	        self.scopes.push(HashMap::new());
283	        self.current_scope += 1;
284	    }
285	
286	    pub fn pop_scope(&mut self) {
287	        self.scopes.pop();
288	        self.current_scope -= 1;
289	    }
290	
291	    // Variable Handling
292	
293	    pub fn declare_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
294	        let id = self.next_var_id;
295	        self.next_var_id += 1;
296	
297	        let scope = self.scopes.last_mut().unwrap();
298	        scope.insert(name, (id, is_mutable, var_type));
299	
300	        id
301	    }
302	
303	    pub fn declare_global_var(&mut self, name: String, is_mutable: bool, var_type: Type) -> usize {
304	        let id = self.next_var_id;
305	        self.next_var_id += 1;
306	
307	        let scope = self.scopes.first_mut().unwrap();
308	        scope.insert(name, (id, is_mutable, var_type));
309	
310	        id
311	    }
312	
313	    fn resolve_var(&self, name: &str) -> Option<(usize, usize)> {
314	        for (idx, scope) in self.scopes.iter().enumerate().rev() {
315	            if let Some(id) = scope.get(name) {
316	                return Some((id.0, idx));
317	            }
318	        }
319	        None
320	    }
321	
322	    pub fn get_var(&self, name: &str) -> Option<(bool, Type)> {
323	        for scope in self.scopes.iter().rev() {
324	            if let Some((_id, is_mutable, var_type)) = scope.get(name) {
325	                return Some((*is_mutable, var_type.clone()));
326	            }
327	        }
328	        None
329	    }
330	
331	    pub fn var_exists(&self, name: &str) -> bool {
332	        for scope in self.scopes.iter().rev() {
333	            if let Some(_) = scope.get(name) {
334	                return true;
335	            }
336	        }
337	        false
338	    }
339	
340	    /// Returns the C variable name for variables.\
341	    /// Format: v_{id}s_{scope}
342	    pub fn c_var_name(&self, name: &str, span: Span) -> String {
343	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
344	            error(
345	                span,
346	                format!("Could not find variable '{}'", name).as_str(),
347	                "fetching variable name",
348	            );
349	            (0, 0)
350	        });
351	        format!("v_{}s_{}", id, scope)
352	    }
353	
354	    /// Returns the C variable name for a function instance with generics.\
355	    /// Format: v_{id}s_{scope}C{generic_types}D for generic functions, v_{id}s_{scope}CD for non-generic
356	    pub fn c_func_instance_name(&mut self, name: &str, generics: &[Type], span: Span) -> String {
357	        let (id, scope) = self.resolve_var(name).unwrap_or_else(|| {
358	            error(
359	                span,
360	                format!("Could not find variable '{}'", name).as_str(),
361	                "fetching function name",
362	            );
363	            (0, 0)
364	        });
365	
366	        let mut result = format!("v_{}s_{}", id, scope);
367	
368	        if generics.is_empty() {
369	            // Non-generic function: add CD suffix
370	            result.push_str("CD");
371	        } else {
372	            // Generic function: add C{generics}D
373	            result.push('C');
374	            for (i, g) in generics.iter().enumerate() {
375	                result.push_str(&self.c_type_name(g, span));
376	                if i != generics.len() - 1 {
377	                    result.push('_');
378	                }
379	            }
380	            result.push('D');
381	        }
382	
383	        result
384	    }
385	
386	    // Type Handling
387	
388	    pub fn register_type(&mut self, ty: Type) -> usize {
389	        if let Type::Conceptual(name) = &ty {
390	            panic!("Tried to register conceptual type: {}", name);
391	        }
392	
393	        let canonical_ty = self.canonicalize_type(ty);
394	
395	        if let Some(index) = self.all_types.iter().position(|t| t == &canonical_ty) {
396	            return index;
397	        }
398	
399	        let id = self.next_type_id;
400	        self.next_type_id += 1;
401	
402	        self.all_types.push(canonical_ty);
403	        id
404	    }
405	
406	    /// Returns the position of a type. Does not check if the type is generic
407	    fn get_simple_type_id(&self, name: &str) -> usize {
408	        if let Some(index) = self.all_types.iter().position(|t| t.name() == name) {
409	            return index;
410	        }
411	
412	        0
413	    }
414	    /// Returns the ID of a type. If the type is generic, it registers its generic types
415	    fn get_type_id(&mut self, ty: &Type) -> Option<usize> {
416	        let canonical = self.canonicalize_type(ty.clone());
417	        self.all_types.iter().position(|t| t == &canonical)
418	    }
419	
420	    /// Registers the generic types in a generic type
421	    fn canonicalize_type(&mut self, ty: Type) -> Type {
422	        let canonical_generics: Vec<Type> = ty
423	            .generics()
424	            .iter()
425	            .map(|g| {
426	                let id = self.register_type(g.clone());
427	                self.all_types[id].clone()
428	            })
429	            .collect();
430	
431	        if canonical_generics.is_empty() {
432	            ty
433	        } else {
434	            Type::with_generics(ty.name(), canonical_generics)
435	        }
436	    }
437	
438	    /// Internal helper that generates the type name without the CD suffix
439	    fn c_type_name_raw(&mut self, ty: &Type, span: Span) -> String {
440	        // Check if this is a function type (has "func" as its name)
441	        if ty.name() == "func" {
442	            // For function types, use the mangled format: t_5C{param_types,return_type}D
443	            let gens = ty.generics();
444	            let mut name = String::from("t_5C");
445	
446	            // Add all generics (args + return type) separated by underscore
447	            for (i, g) in gens.iter().enumerate() {
448	                name.push_str(&self.c_type_name_raw(g, span));
449	                if i != gens.len() - 1 {
450	                    name.push('_');
451	                }
452	            }
453	
454	            // Close with D
455	            name.push('D');
456	
457	            name
458	        } else {
459	            // For non-function types, use the standard ID-based naming
460	            let type_id = self.get_type_id(ty).unwrap_or_else(|| {
461	                error(
462	                    span,
463	                    format!("Could not find type '{}'", ty).as_str(),
464	                    "transpiling",
465	                );
466	                0
467	            });
468	
469	            format!("t_{}", type_id)
470	        }
471	    }
472	
473	    /// Public API: returns type name with CD suffix for non-generic consistency.\
474	    /// For function types, the mangling already ends with D, so no additional CD.\
475	    /// For non-function types, add CD suffix.\
476	    /// \
477	    /// Format for simple types: t_{id}\
478	    /// Format for generic types and for simple functions: t_{id}C{generic types}D\
479	    /// Format for generic functions: t_{id}C{argument types, return type}DC{generic types}D\
480	    /// ^^^Note that generic types, argument types and return type are separated by "_".
481	    pub fn c_type_name(&mut self, ty: &Type, span: Span) -> String {
482	        let name = self.c_type_name_raw(ty, span);
483	
484	        // For function types, the raw name already ends with D, so don't add CD
485	        if ty.name() == "func" {
486	            name
487	        } else {
488	            // For non-function types, add CD suffix for consistency
489	            let mut result = name;
490	            result.push_str("CD");
491	            result
492	        }
493	    }
494	
495	    pub fn add_func_type(
496	        &mut self,
497	        ret_type: Type,
498	        arg_types: Vec<Type>,
499	        ctx: &mut CodeGenContext,
500	        span: Span,
501	    ) {
502	        // Generate the function type name using the mangling scheme
503	        // Format: t_5C{args, ret}DC{gens}D
504	        let mut gens = arg_types.clone();
505	        gens.push(ret_type.clone());
506	        let func_type = Type::with_generics("func", gens);
507	
508	        if self.get_type_id(&func_type).is_some() {
509	            return;
510	        }
511	
512	        self.register_type(func_type.clone());
513	
514	        let func_type_name = self.c_type_name(&func_type, span);
515	
516	        // Generate the typedef for the function type
517	        ctx.types.push_str("typedef ");
518	        ctx.types.push_str(&self.c_type_name(&ret_type, span));
519	        ctx.types.push_str(&format!("(*{})", func_type_name));
520	        ctx.types.push('(');
521	        for ty in arg_types.iter() {
522	            ctx.types.push_str(&self.c_type_name(&ty, span));
523	            ctx.types.push(',');
524	        }
525	        if arg_types.len() >= 1 {
526	            ctx.types.pop();
527	        }
528	        ctx.types.push_str(");\n");
529	    }
530	
531	    pub fn push_this(&mut self, this: &str) {
532	        self.these.push(this.to_string());
533	    }
534	    pub fn pop_this(&mut self) {
535	        self.these.pop();
536	    }
537	    pub fn this(&self) -> &str {
538	        &self.these.last().unwrap()
539	    }
540	
541	    pub fn del_var(&mut self, name: &str) {
542	        for scope in self.scopes.iter_mut().rev() {
543	            if let Some(_id) = scope.get(name) {
544	                scope.remove(name);
545	            }
546	        }
547	    }
548	
549	    pub fn complete(&mut self, _ctx: &mut CodeGenContext) {
550	        todo!("This function is currently not implemented");
551	    }
552	}
