7	/// Helper to get the first token's type
8	fn tokenize_first(source: &str) -> TokenType {
9	    let mut scanner = Scanner::new(source.to_string());
10	    let tokens = scanner.scan_tokens();
11	    tokens.first().map(|t| t.token_type).unwrap_or(TokenType::EOF)
12	}
13	
14	/// Helper to get all token types from source
15	fn tokenize_all(source: &str) -> Vec<TokenType> {
16	    let mut scanner = Scanner::new(source.to_string());
17	    let tokens = scanner.scan_tokens();
18	    tokens.iter().map(|t| t.token_type).collect()
19	}
20	
21	/// Helper to get token literal value
22	fn tokenize_literal(source: &str) -> Option<String> {
23	    let mut scanner = Scanner::new(source.to_string());
24	    let tokens = scanner.scan_tokens();
25	    tokens.first().map(|t| t.literal.clone())
26	}
