490	#[test]
491	fn test_nested_block_comment() {
492	    // Note: Obstruct doesn't support nested comments
493	    // The first */ closes the comment, leaving " outer */" after it
494	    // "outer" after first */ becomes an identifier
495	    let tokens = tokenize_all("/* outer /* inner */ outer */");
496	    // "outer" becomes Ident, then */ is just two tokens, then EOF
497	    assert!(tokens.contains(&TokenType::Ident));
498	    assert!(tokens.contains(&TokenType::EOF));
